const response = $input.first().json;
const rawText = response.content?.[0]?.text || '';

function parseSections(text) {
  const sections = [];
  const rx = /=== SEKTION: (.+?) ===([\s\S]*?)(?==== SEKTION:|$)/g;
  let m;
  while ((m = rx.exec(text)) !== null) {
    sections.push({ name: m[1].trim(), content: m[2].trim() });
  }
  return sections;
}

function parseLinkedIn(content) {
  const posts = [];
  const blocks = content.split(/^---$/m);
  for (const block of blocks) {
    if (!block.trim()) continue;
    const p = {};
    for (const line of block.trim().split('\n')) {
      const idx = line.indexOf(': ');
      if (idx < 0) continue;
      const k = line.substring(0, idx).trim();
      const v = line.substring(idx + 2).trim();
      if (k === 'AUTHOR')    p.author = v;
      if (k === 'POSITION')  p.jobTitle = v;
      if (k === 'COMPANY')   p.company = v;
      if (k === 'DATE')      p.date = v;
      if (k === 'REACTIONS') p.reactions = parseInt(v) || 0;
      if (k === 'URL')       p.url = v;
      if (k === 'TEXT')      p.text = v;
    }
    if (p.author && p.text) posts.push(p);
  }
  return posts;
}

function parseBullets(content) {
  return content.split('\n')
    .filter(l => l.trim().startsWith('-'))
    .map(l => l.replace(/^-\s*/, '').trim())
    .filter(Boolean);
}

const PLACEHOLDER = ['[nicht angegeben]','[nicht verfügbar]','[unbekannt]','k.a.','leer','keine angabe','n/a'];
const isPlaceholder = v => !v || PLACEHOLDER.some(p => v.toLowerCase().trim() === p || v.toLowerCase().includes('k.a.'));

const esc = s => (s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
const md = s => esc(s||'')
  .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
  .replace(/\*(.+?)\*/g, '<em>$1</em>')
  .replace(/\[([^\]]+)\]\((https?:\/\/[^)]+)\)/g, '<a href="$2" style="color:#3b82f6;text-decoration:underline;">$1</a>');

const sections = parseSections(rawText);
const date = new Date().toLocaleDateString('de-DE', {day:'2-digit', month:'long', year:'numeric'});

let sectionsHtml = '';

for (const sec of sections) {

  if (sec.name === 'LINKEDIN-RADAR') {
    const posts = parseLinkedIn(sec.content);
    if (!posts.length) continue;
    let cards = '';
    for (const p of posts) {
      const initials = (p.author||'?').split(' ').map(w=>w[0]||'').join('').substring(0,2).toUpperCase();
      const hasUrl = p.url && p.url.startsWith('http');
      const jobTitle = isPlaceholder(p.jobTitle) ? '' : p.jobTitle;
      const company  = isPlaceholder(p.company)  ? '' : p.company;
      const showDate = p.date && !isPlaceholder(p.date);
      const subtitle = [jobTitle, company].filter(Boolean).join(' · ');
      cards += `
<div style="background:#fff;border:1px solid #e2e8f0;border-radius:12px;padding:20px;margin-bottom:12px;border-left:4px solid #3b82f6;">
  <table width="100%" cellpadding="0" cellspacing="0" style="margin-bottom:12px;">
    <tr>
      <td width="44" valign="middle">
        <div style="width:44px;height:44px;border-radius:50%;background:linear-gradient(135deg,#3b82f6,#1d4ed8);color:#fff;text-align:center;line-height:44px;font-weight:700;font-size:14px;">${esc(initials)}</div>
      </td>
      <td style="padding-left:12px;" valign="middle">
        <div style="font-weight:700;color:#0f172a;font-size:14px;">${esc(p.author||'')}</div>
        ${subtitle ? `<div style="color:#64748b;font-size:12px;">${esc(subtitle)}</div>` : ''}
      </td>
      <td align="right" valign="middle">
        ${showDate ? `<div style="color:#94a3b8;font-size:11px;">${esc(p.date)}</div>` : ''}
        ${p.reactions ? `<div style="color:#3b82f6;font-size:12px;font-weight:600;">👍 ${p.reactions}</div>` : ''}
      </td>
    </tr>
  </table>
  <p style="color:#334155;font-size:14px;line-height:1.6;margin:0 0 14px;font-style:italic;border-left:3px solid #bfdbfe;padding-left:12px;">${esc(p.text||'')}</p>
  ${hasUrl ? `<a href="${esc(p.url)}" style="display:inline-block;background:#3b82f6;color:#fff;text-decoration:none;padding:8px 18px;border-radius:6px;font-size:12px;font-weight:700;letter-spacing:0.3px;">→ Zum Post</a>` : ''}
</div>`;
    }
    sectionsHtml += `
<div style="margin-bottom:36px;">
  <table width="100%" cellpadding="0" cellspacing="0" style="margin-bottom:16px;">
    <tr>
      <td style="background:#eff6ff;border-left:4px solid #3b82f6;border-radius:0 8px 8px 0;padding:12px 16px;">
        <span style="font-size:16px;font-weight:800;color:#0f172a;">📣 LinkedIn-Radar</span>
        <span style="float:right;font-size:11px;color:#94a3b8;margin-top:2px;">${posts.length} Posts</span>
      </td>
    </tr>
  </table>
  ${cards}
</div>`;
  }

  else if (sec.name === 'AUSSCHREIBUNGEN') {
    const items = parseBullets(sec.content);
    if (!items.length) continue;
    let rows = items.map(item => `
<tr>
  <td style="padding:10px 0;border-bottom:1px solid #f1f5f9;color:#334155;font-size:14px;line-height:1.5;">
    <span style="display:inline-block;width:8px;height:8px;background:#22c55e;border-radius:50%;margin-right:8px;vertical-align:middle;"></span>
    ${md(item)}
  </td>
</tr>`).join('');
    sectionsHtml += `
<div style="margin-bottom:36px;">
  <table width="100%" cellpadding="0" cellspacing="0" style="margin-bottom:16px;">
    <tr><td style="background:#f0fdf4;border-left:4px solid #22c55e;border-radius:0 8px 8px 0;padding:12px 16px;">
      <span style="font-size:16px;font-weight:800;color:#0f172a;">💎 Ausschreibungen</span>
    </td></tr>
  </table>
  <table width="100%" cellpadding="0" cellspacing="0">${rows}</table>
</div>`;
  }

  else {
    const ICONS   = { PERSONAL:'🔥', DIGITALISIERUNG:'🤖', FLURFUNK:'💬', 'GKV-NACHRICHTEN':'🏥' };
    const LABELS  = { PERSONAL:'Personal & Vorstand', DIGITALISIERUNG:'Digitalisierung & IT', FLURFUNK:'Flurfunk', 'GKV-NACHRICHTEN':'GKV-Nachrichten' };
    const icon    = ICONS[sec.name]  || '📌';
    const label   = LABELS[sec.name] || sec.name;
    const items   = parseBullets(sec.content);
    let body = '';
    if (items.length) {
      body = items.map(item => `
<tr><td style="padding:8px 0;border-bottom:1px solid #f1f5f9;color:#334155;font-size:14px;line-height:1.5;">
  <span style="color:#64748b;margin-right:8px;">›</span>${md(item)}
</td></tr>`).join('');
      body = `<table width="100%" cellpadding="0" cellspacing="0">${body}</table>`;
    } else {
      body = `<p style="color:#334155;font-size:14px;line-height:1.6;margin:0;">${md(sec.content)}</p>`;
    }
    sectionsHtml += `
<div style="margin-bottom:36px;">
  <table width="100%" cellpadding="0" cellspacing="0" style="margin-bottom:16px;">
    <tr><td style="background:#f8fafc;border-left:4px solid #64748b;border-radius:0 8px 8px 0;padding:12px 16px;">
      <span style="font-size:16px;font-weight:800;color:#0f172a;">${icon} ${esc(label)}</span>
    </td></tr>
  </table>
  ${body}
</div>`;
  }
}

if (!sectionsHtml) {
  sectionsHtml = '<p style="color:#64748b;font-size:14px;">Heute keine relevanten Meldungen verfügbar.</p>';
}

const html = `<!DOCTYPE html>
<html lang="de">
<head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>
<body style="margin:0;padding:0;background:#dbeafe;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Arial,sans-serif;">
<div style="max-width:680px;margin:0 auto;padding:32px 16px 48px;">

  <div style="background:linear-gradient(150deg,#0f172a 0%,#1e3a5f 60%,#1d4ed8 100%);border-radius:16px 16px 0 0;padding:40px 44px 32px;text-align:center;">
    <div style="font-size:10px;font-weight:800;letter-spacing:5px;text-transform:uppercase;color:#60a5fa;margin-bottom:12px;">GKV Intelligence Brief</div>
    <div style="font-size:36px;font-weight:900;color:#f8fafc;letter-spacing:-1px;margin-bottom:6px;">KassenInfodienst</div>
    <div style="font-size:13px;color:#93c5fd;margin-bottom:24px;">Fakten · Zahlen · Namen</div>
    <div style="display:inline-block;background:rgba(255,255,255,0.08);border:1px solid rgba(255,255,255,0.15);border-radius:20px;padding:6px 18px;font-size:12px;color:#bfdbfe;">
      📅 ${date}
    </div>
  </div>

  <div style="height:4px;background:linear-gradient(90deg,#3b82f6,#60a5fa,#93c5fd);"></div>

  <div style="background:#fff;padding:40px 44px;border-radius:0 0 16px 16px;border:1px solid #bfdbfe;border-top:none;">
    ${sectionsHtml}
  </div>

  <div style="text-align:center;margin-top:24px;color:#64748b;font-size:11px;line-height:2;">
    KassenInfodienst &nbsp;·&nbsp; Claude Sonnet 4.6 &nbsp;·&nbsp; ${date}
  </div>
</div>
</body>
</html>`;

return [{ json: { newsletter_text: rawText, newsletter_html: html, generated_at: new Date().toISOString() } }];

const items = $input.all();
const linkedinItems = items.filter(i => i.json._source === 'LinkedIn').slice(0, 15);
const otherItems = items.filter(i => i.json._source !== 'LinkedIn');

const GKV_TERMS = ['krankenkasse','gkv','bitmarck','itsc','gematik','beitrag',
  'fusion','vorstand','digitalisierung','ausschreibung','kasse','versicherung',
  'krankenversicherung','kassenvorstand','epa','telematik','ti 2','ti2'];
const HIGH_TERMS = ['fusion','fusionierung','vorstandswechsel','bitmarck','itsc',
  'ausschreibung','insolvenz','gematik','epa ','ti 2','providerwechsel','govdigital',
  '21c','zusammenschluss'];

function scoreItem(item) {
  const text = ((item.json.title||'') + ' ' + (item.json.contentSnippet||item.json.text||'')).toLowerCase();
  let s = 0;
  if (HIGH_TERMS.some(t => text.includes(t))) s += 3;
  if (GKV_TERMS.some(t => text.includes(t))) s += 2;
  return s;
}

const topOthers = otherItems
  .map(i => ({ ...i, json: { ...i.json, _score: scoreItem(i) } }))
  .filter(i => i.json._score >= 2)
  .sort((a, b) => b.json._score - a.json._score)
  .slice(0, 20);

const selected = [...linkedinItems, ...topOthers];

let text = `=== STATISTIK ===\nGesamt: ${selected.length} Einträge\nLinkedIn-Posts: ${linkedinItems.length}\n=================\n\n`;

if (linkedinItems.length > 0) {
  text += `=== LINKEDIN-POSTS (exakt so übernehmen, keine Felder weglassen) ===\n\n`;
  for (const item of linkedinItems) {
    text += `AUTHOR: ${item.json.author || 'Unbekannt'}\n`;
    text += `POSITION: ${item.json.authorTitle || ''}\n`;
    text += `COMPANY: ${item.json.authorCompany || ''}\n`;
    text += `DATE: ${item.json.postedAt || ''}\n`;
    text += `REACTIONS: ${item.json.reactions || 0}\n`;
    text += `URL: ${item.json.link || ''}\n`;
    text += `TEXT: ${(item.json.text || '').substring(0, 280)}\n`;
    text += `---\n`;
  }
  text += `\n`;
}

for (const item of topOthers) {
  const src = item.json._source || 'Unbekannt';
  const title = item.json.title || item.json.text?.substring(0, 100) || '';
  const url = item.json.url || item.json.link || '';
  const date = item.json.pubDate || item.json.postedAt || '';
  const body = item.json.contentSnippet || item.json.text?.substring(0, 300) || '';
  text += `### [${src}] ${title}\n`;
  if (date) text += `Datum: ${date}\n`;
  if (url) text += `URL: ${url}\n`;
  if (body) text += `${body}\n\n`;
}

const clean = text.replace(/[\uD800-\uDFFF]/g, '');
return [{ json: { haiku_scored: clean, item_count: selected.length, linkedin_count: linkedinItems.length } }];

const items = $input.all();
const seen = new Set();
const fresh = [];

for (const item of items) {
  const key = item.json.url || item.json.link || item.json.id ||
              (item.json.title || '') + (item.json.text || '').substring(0, 80);
  const hash = String(key || Math.random()).replace(/\s+/g, '').toLowerCase();
  if (!seen.has(hash)) {
    seen.add(hash);
    fresh.push({ ...item, json: { ...item.json, _hash: hash } });
  }
}

const cutoff = new Date();
cutoff.setDate(cutoff.getDate() - 2);

return fresh.filter(item => {
  if (item.json._source === 'LinkedIn') return true;
  const pub = item.json.pubDate || item.json.postedAt || item.json['publication-date'];
  if (!pub) return true;
  return new Date(pub) >= cutoff;
});

const BASE = "https://linkdapi.com/api/v1/search/posts";
const C = {
  bitmarck: "955964", itsc: "8195481", gematik: "125822",
  dak: "42928985", tk: "41317", barmer: "18012268",
  hkk: "10699871", hek: "36667598", kkh: "39196",
  ikk: "1412986", viactiv: "12414104"
};

const queries = [
  { keyword: "ePA",             authorCompany: C.gematik },
  { keyword: "Telematik",       authorCompany: C.gematik },
  { keyword: "Cloud",           authorCompany: C.bitmarck, authorJobTitle: "CIO" },
  { keyword: "Atlassian",       authorCompany: C.bitmarck },
  { keyword: "SAP",             authorCompany: C.bitmarck },
  { keyword: "Digitalisierung", authorCompany: C.bitmarck },
  { keyword: "IT-Strategie",    authorCompany: C.itsc },
  { keyword: "Cloud",           authorCompany: C.itsc },
  { keyword: "ePA",             authorCompany: C.dak,     authorJobTitle: "Vorstand" },
  { keyword: "Digitalisierung", authorCompany: C.tk,      authorJobTitle: "CIO" },
  { keyword: "NIS2",            authorCompany: C.barmer },
  { keyword: "ePA",             authorCompany: C.tk },
  { keyword: "Digitalisierung", authorJobTitle: "CIO" },
  { keyword: "NIS2",            authorJobTitle: "Vorstand" },
  { keyword: "ePA",             authorJobTitle: "CIO" },
];

return queries.map(q => {
  let url = BASE + "?keyword=" + encodeURIComponent(q.keyword)
    + "&sortBy=relevance&datePosted=past-week&count=10";
  if (q.authorCompany)  url += "&authorCompany="  + q.authorCompany;
  if (q.authorJobTitle) url += "&authorJobTitle=" + encodeURIComponent(q.authorJobTitle);
  return { json: { url, ...q } };
});

const results = [];

for (const item of $input.all()) {
  const body = item.json;
  const posts = body.data?.posts ?? body.data ?? body.posts ?? body.results ?? (Array.isArray(body) ? body : []);

  for (const post of posts) {
    const eng = post.engagements ?? {};
    const reactions = eng.totalReactions ?? eng.totalReactionCount ?? 0;
    const author = post.author ?? post.actor ?? {};
    const postedAtMs = post.postedAt?.timestamp ?? post.postedAt ?? '';
    const dateStr = postedAtMs ? new Date(Number(postedAtMs)).toLocaleDateString('de-DE') : '';

    results.push({ json: {
      _source:        'LinkedIn',
      title:          (author.name ?? '') + ': ' + (post.text ?? '').slice(0, 120),
      text:           post.text ?? '',
      link:           post.postURL ?? post.url ?? post.postUrl ?? '',
      postedAt:       dateStr,
      reactions,
      comments:       eng.commentsCount ?? eng.commentCount ?? 0,
      author:         author.name ?? author.fullName ?? '',
      authorTitle:    author.headline ?? author.title ?? '',
      authorCompany:  author.companyName ?? author.company ?? '',
      authorImageUrl: author.profilePictureURL ?? author.profilePicture ?? author.picture ?? '',
      postImageUrl:   post.image?.url ?? post.images?.[0]?.url ?? '',
      contentSnippet: `${author.name ?? ''}: ${(post.text ?? '').substring(0, 300)}`,
    }});
  }
}

return results;
